function onNavigation(a){2==a.progress&&player.pause()}
Flowtime.showProgress(!0),Flowtime.addEventListener("flowtimenavigation",onNavigation,!1),Flowtime.start(),
$(function(){
	$(".nojavascript").remove();
	setInterval(function(){$(".showtip").removeClass("showtip").hide().siblings("span").addClass("showtip").fadeIn()},5e3);
	$("#write-submit").click(function(){
		for(var a={},b=1;79>b;b++)a[b]=$("#text-"+b).text();
		$(".write-ok").fadeIn(),$("#text-href").focus();
		$("#back").click(function(){$(".write-ok").fadeOut()});
		$("#write-post").click(function(){
			var b=$("#text-href").text(),c=$("#text-music").text();
			""==b.replace(/\s+/g,"")?($("#write-url i").text("\u2190 cannot be empty").fadeIn(),$("#text-href").focus(),setTimeout(function(){$("#write-url i").fadeOut()},3e3)):
			/^[\w\-]{3,30}$/.test(b)?(""==c.replace(/\s+/g,"")?($("#write-mp3 i").text("\u2190 cannot be empty").fadeIn(),$("#text-music").focus(),setTimeout(function(){$("#write-mp3 i").fadeOut()},3e3)):
			/^(http|https):\/\/+([\w-]+\.)+[\w-]+(\/[\w-.\/?%&=]*)?$/.test(c)?(
				$("#back").html('<img src="img/loading.gif" alt="loading">'),
				$("#write-post").text("Generating page...").attr("disabled",!0).addClass("disabled"),
				$.post("love.php?add",{textHref:b,textMusic:c,textArr:a},function(a){
					1==a.status?(
						$("#back").hide(),
						$(".write-ok p").hide(),
						$(".write-ok div button").hide(),
						$(".write-ok div h2").hide().text("Confession page generated successfully \u2764").fadeIn(),
						$("#write-url").html('Your confession link is: <a href="'+a.url+'" target="_blank">'+a.url+"</a>").fadeIn(),
						$(".write-share").css("display","inline-block").children("p").show()
					):0==a.status&&(
						$("#write-url i").text(a.msg).fadeIn(),
						$("#text-href").focus(),
						setTimeout(function(){$("#write-url i").fadeOut()},3e3),
						$("#back").text("Edit again"),
						$("#write-post").text("\u2764 Generate confession page").attr("disabled",!1).removeClass("disabled")
					)
				},"json")
			):($("#write-mp3 i").text("\u2190 Link not allowed").fadeIn(),$("#text-music").focus(),setTimeout(function(){$("#write-mp3 i").fadeOut()},3e3))):
			($("#write-url i").text("\u2190 Incorrect format").fadeIn(),$("#text-href").focus(),setTimeout(function(){$("#write-url i").fadeOut()},3e3))
		})
	})
});
var bgmMusic=document.getElementById("bgmMusic");
$("#on").click(function(){bgmMusic.pause(),$("#on").hide(200),$("#off").css({display:"inline-block"},300)});
$("#off").click(function(){bgmMusic.play(),$("#off").hide(200),$("#on").css({display:"inline-block"},300)});